INSERT INTO program_phases (id, protocol_id, phase_number, label, range_text, icon, focus, science) VALUES (8, 4, 1, 'Thanh Lọc & Nhận Thức', 'Ngày 1–30', '🧠', 'Ngắt kết nối, đo chỉ số nền tảng (baseline), kiểm soát kích thích và thiết lập ranh giới môi trường.', 'Tăng nhạy cảm thụ thể Dopamine (Nestler, 2004); Kiểm soát kích thích (Koob & Volkow, 2016).');
INSERT INTO program_phases (id, protocol_id, phase_number, label, range_text, icon, focus, science) VALUES (9, 4, 2, 'Củng Cố Nền Tảng', 'Ngày 31–60', '⚡', 'Xây dựng thói quen thay thế, nâng cao khả năng chống chịu cảm xúc khó chịu và tái thiết lập quan hệ xã hội.', 'Hình thành thói quen (Lally et al., 2010); Củng cố hành vi dựa trên chánh niệm (Garland et al., 2017).');
INSERT INTO program_phases (id, protocol_id, phase_number, label, range_text, icon, focus, science) VALUES (10, 4, 3, 'Tích Hợp Vào Cuộc Sống', 'Ngày 61–90', '🌱', 'Phát triển bản sắc mới, ứng dụng sáng tạo ngoại tuyến và tối ưu hóa sức khỏe thể chất.', 'Lý thuyết Tự quyết (Deci & Ryan, 2000); Củng cố thói quen dựa trên bản sắc (identity-based) (Clear, 2018).');
INSERT INTO program_phases (id, protocol_id, phase_number, label, range_text, icon, focus, science) VALUES (11, 4, 4, 'Làm Chủ Hoàn Toàn', 'Ngày 91–120', '🏆', 'Thiết lập lối sống lối sống tối giản số (digital minimalism) dài hạn, đóng góp giá trị cộng đồng và làm chủ mức dopamine nền tảng (baseline).', 'Lối sống tối giản số (Newport, 2019); Mô hình PERMA (Seligman, 2011).');
