USE `exe_db`;

-- Temporarily disable FK checks to allow clean metadata re-seed without deleting user data
SET FOREIGN_KEY_CHECKS = 0;

-- Allow week_id to be nullable (tasks for protocol 1 are indexed by day_id only)
ALTER TABLE `program_tasks_metadata` MODIFY COLUMN `week_id` BIGINT NULL;
ALTER TABLE `program_metrics_metadata` MODIFY COLUMN `week_id` BIGINT NULL;

-- Clear existing metadata
DELETE FROM `program_tasks_metadata`;
DELETE FROM `program_metrics_metadata`;
DELETE FROM `program_days`;
DELETE FROM `program_weeks`;
DELETE FROM `program_phases`;
DELETE FROM `protocol_selections`;
DELETE FROM `quiz_recommendations`;
DELETE FROM `protocols`;

SET FOREIGN_KEY_CHECKS = 1;













-- Tasks Metadata
DELETE FROM `program_tasks_metadata`;

-- Metrics Metadata
DELETE FROM `program_metrics_metadata`;
